package com.anvritai.abhay.api;import com.anvritai.abhay.security.UserPrincipal;import com.anvritai.abhay.service.EnterpriseExportService;import java.util.UUID;import org.springframework.http.ResponseEntity;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/companies/{companyId}") public class EnterpriseExportController{private final EnterpriseExportService service;public EnterpriseExportController(EnterpriseExportService s){service=s;}@GetMapping("/exports/{resource}")public ResponseEntity<byte[]> export(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId,@PathVariable String resource,@RequestParam(defaultValue="JSON")String format){return service.export(p.id(),companyId,resource,format);}@PostMapping("/backup")public ResponseEntity<byte[]> backup(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId){return service.backup(p.id(),companyId);}}
